CRITICAL_DIMENSIONS = {'groundedness', 'safety', 'clinical_accuracy'}

def aggregate_with_hard_fail(
    scores: dict,  # {dimension: score}
    weights: dict,
    critical_dims: set = CRITICAL_DIMENSIONS,
    hard_fail_threshold: int = 1,
) -> dict:
    triggered = [d for d in critical_dims
                 if scores.get(d, 99) <= hard_fail_threshold]
    weighted = sum(weights.get(d, 0) * v for d, v in scores.items())
    return {
        'score': weighted,
        'hard_fail': len(triggered) > 0,
        'hard_fail_dims': triggered,
        'effective_score': 0.0 if triggered else weighted,
    }

import random
from dataclasses import dataclass, field

@dataclass
class AnnotationTask:
    task_id: str
    question: str
    context: str
    response: str
    is_gold: bool = False
    gold_scores: dict = field(default_factory=dict)  # {dim: expected_score}

def build_annotation_queue(
    tasks: list[AnnotationTask],
    gold_items: list[AnnotationTask],
    gold_fraction: float = 0.08,
) -> list[AnnotationTask]:
    """Interleave gold items into task queue and shuffle."""
    n_gold = max(1, int(len(tasks) * gold_fraction))
    selected_gold = random.sample(gold_items, min(n_gold, len(gold_items)))
    for g in selected_gold:
        g.is_gold = True
    combined = tasks + selected_gold
    random.shuffle(combined)
    return combined

def rater_accuracy_on_gold(
    annotations: list[dict],   # [{task_id, dim, score}]
    gold_map: dict,            # {task_id: {dim: expected}}
    tolerance: int = 0,
) -> float:
    gold_ann = [a for a in annotations if a['task_id'] in gold_map]
    if not gold_ann:
        return 1.0
    correct = sum(
        1 for a in gold_ann
        if abs(a['score'] - gold_map[a['task_id']].get(a['dim'], -99)) <= tolerance
    )
    return correct / len(gold_ann)
